    saveSettings(userSettings);

    await ctx.answerCbQuery(`Выбрано: ${model}`);

    await ctx.editMessageText(`Теперь я использую модель: ${model}`, { 
      parse_mode: 'Markdown',
      reply_markup: {
        inline_keyboard: [
          [{ text: ' Назад к выбору моделей', callback_data: 'back_to_menu' }]
        ]
      }
    });

  } else if (data === 'back_to_menu') {
    await ctx.answerCbQuery();
    await ctx.editMessageText('Выберите модель ИИ:', getMainMenuKeyboard());
